int xlnx_gpio_out_read(xlnx_gpio_out_t* gpio, uint16_t* data);

// Toggle the selected pin(s) switching 0 and 1 back and forth
int xlnx_gpio_out_toggle(xlnx_gpio_out_t* gpio, pin_t pin);

